-- ═══════════════════════════════════════════════════════════════════
-- CodeQuest · Migración 016 — SQL con Oracle · m3b: Del modelo al esquema Oracle
-- ═══════════════════════════════════════════════════════════════════
-- Cubre la Parte V (legibilidad del ERD: espagueti vs limpio,
-- entidades de gran volumen, subdiagramas por área funcional), la
-- Parte VI COMPLETA (mapeo: entidad→tabla, atributo→columna, UID→PK,
-- relación→FK; 1:M, M:M/intersección, 1:1, FK dentro del UID,
-- histórico, arcos con FKs opcionales + CHECK, subtipos en sus tres
-- estrategias con discriminadora y PK compartida) y la Parte VIII
-- (nomenclatura Oracle por versión, SDLC y matriz CRUD).
-- Diagramas 6.1 (espagueti vs limpio), 7.1 (tres estrategias de
-- subtipos) y 8.1 (SDLC) con NetworkDiagram data-driven.
-- Precisiones vinculantes: la intersección NO siempre lleva solo las
-- 2 FKs como PK; una FK referencia PK o UNIQUE compatible;
-- identificadores 30 BYTES hasta 12.1 y 128 desde 12.2.
-- Reglas de contenido: quizzes autocontenidos o con términos técnicos.
-- OJO: SQL con Oracle está PUBLICADO — esta migración sale en vivo.
-- Idempotente: borra y recrea las lecciones de ESTE módulo.
-- Ejecutar DESPUÉS de 011 (estructura v2).
-- ═══════════════════════════════════════════════════════════════════

-- Limpia el módulo (cascade borra sus content_blocks)
delete from public.lessons
where module_id = (
  select m.id
  from public.modules m
  join public.courses c on c.id = m.course_id
  where c.slug = 'sql-oracle' and m.slug = 'm3b-modelo-a-oracle'
);

-- ── Lecciones del módulo ──────────────────────────────────────────────
insert into public.lessons (module_id, slug, title, kind, xp, sort_order)
select m.id, v.slug, v.title, v.kind, v.xp, v.ord
from public.modules m
join public.courses c on c.id = m.course_id,
     (values
       ('m3b-l01-legibilidad',    'Un ERD que se deja leer',              'leccion',  20, 1),
       ('m3b-l02-mapeo-basico',   'El mapeo: de entidades a tablas',      'leccion',  20, 2),
       ('m3b-l03-intersecciones', 'Intersecciones, 1:1 y la FK en la PK', 'leccion',  20, 3),
       ('m3b-l04-arcos-subtipos', 'Arcos y subtipos en físico',           'leccion',  20, 4),
       ('m3b-l05-nomenclatura',   'Nomenclatura Oracle',                  'leccion',  20, 5),
       ('m3b-l06-sdlc-crud',      'El ciclo de vida y la matriz CRUD',    'leccion',  20, 6),
       ('m3b-l07-practica-mapeo', 'Práctica: la hoja de mapeo',           'practica', 20, 7),
       ('m3b-x01-examen',         'Examen: Del modelo al esquema',        'examen',   40, 8)
     ) as v(slug, title, kind, xp, ord)
where c.slug = 'sql-oracle' and m.slug = 'm3b-modelo-a-oracle';

-- ═════════════════════════════════════════════════════════════════════
-- L01 · Un ERD que se deja leer (+ Diagrama 6.1)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El modelo también se presenta","body":"Un ERD correcto pero ilegible fracasa igual que uno incorrecto: el modelo se PRESENTA — al equipo, al cliente, al comité que aprueba el proyecto — y un diagrama donde las líneas se cruzan como espagueti no convence a nadie, aunque cada relación esté bien pensada. La legibilidad no es cosmética: es la diferencia entre un modelo que el negocio puede validar ('sí, así funcionan nuestras citas') y uno que solo su autor entiende. Las reglas del oficio: MINIMIZAR los cruces de líneas, no atravesar entidades con relaciones, dejar aire entre cajas, y agrupar cerca lo que se relaciona mucho. El mismo modelo, reacomodado, pasa de jeroglífico a argumento."}$j$),
  (2, 'diagrama', $j${"title":"Diagrama 6.1 · El mismo modelo, dos destinos","component":"NetworkDiagram","props":{"label":"Espagueti vs limpio: idénticas entidades, idénticas relaciones","ancho":520,"alto":400,"grupos":[{"id":"antes","x":14,"y":30,"w":492,"h":160,"titulo":"ANTES — espagueti","descripcion":"Las mismas cuatro entidades del hospital, regadas sin criterio: las relaciones se cruzan en el centro y el ojo tiene que desenredarlas. El comité que valida este modelo se pierde en el minuto uno."},{"id":"despues","x":14,"y":210,"w":492,"h":180,"titulo":"DESPUÉS — reacomodado","descripcion":"Cero información nueva, cero cruces: CITA — la entidad de gran volumen, la que se relaciona con todas — se mueve a la izquierda y las demás se alinean. El modelo ahora se lee como una frase."}],"nodos":[{"id":"paciente","x":30,"y":60,"w":120,"h":44,"titulo":"PACIENTE","descripcion":"En la versión espagueti quedó arriba a la izquierda… lejos de CITA, con quien más se relaciona."},{"id":"cita","x":370,"y":60,"w":120,"h":44,"titulo":"CITA","descripcion":"La entidad que se conecta con todas quedó en una esquina: cada relación tiene que cruzar el diagrama entero para alcanzarla."},{"id":"medico","x":30,"y":130,"w":120,"h":44,"titulo":"MÉDICO","descripcion":"Su relación con CITA cruza en diagonal todo el lienzo… y se intersecta con la de PACIENTE→CONSULTORIO."},{"id":"consultorio","x":350,"y":130,"w":140,"h":44,"titulo":"CONSULTORIO","descripcion":"Cuarta entidad del enredo: las diagonales que llegan y salen se cruzan en el centro del diagrama."},{"id":"cita2","x":40,"y":270,"w":130,"h":56,"titulo":"CITA","tag":"gran volumen","descripcion":"La corrección clave: la entidad de GRAN VOLUMEN — la que acumula filas sin parar y se relaciona con todas — se coloca arriba a la izquierda, y las patas de gallo de sus relaciones apuntan hacia ella sin cruzarse."},{"id":"paciente2","x":330,"y":225,"w":160,"h":40,"titulo":"PACIENTE","descripcion":"Alineado a la derecha, a un enlace recto de CITA. Sin cruces, sin diagonales."},{"id":"medico2","x":330,"y":280,"w":160,"h":40,"titulo":"MÉDICO","descripcion":"Mismo patrón: cada entidad 'uno' en su carril, la entidad 'muchos' a la izquierda."},{"id":"consultorio2","x":330,"y":335,"w":160,"h":40,"titulo":"CONSULTORIO","descripcion":"El tercer carril. Compara con la versión de arriba: mismas relaciones, cero enredo."}],"enlaces":[{"de":"medico","a":"cita","tipo":"flecha","descripcion":"La diagonal MÉDICO→CITA cruza el centro del diagrama…"},{"de":"paciente","a":"consultorio","tipo":"flecha","descripcion":"…y se intersecta con la diagonal PACIENTE→CONSULTORIO: el cruce que vuelve ilegible el modelo."},{"de":"cita2","a":"paciente2","tipo":"flecha","etiqueta":"N:1","descripcion":"Muchas citas por paciente: la pata de gallo queda del lado de CITA, a la izquierda."},{"de":"cita2","a":"medico2","tipo":"flecha","etiqueta":"N:1","descripcion":"Muchas citas por médico: enlace recto, sin cruzar a nadie."},{"de":"cita2","a":"consultorio2","tipo":"flecha","etiqueta":"N:1","descripcion":"Muchas citas por consultorio: el abanico completo, legible de un vistazo."}],"hint":"Compara los dos grupos: mismas entidades, distinto acomodo."},"caption":"Legibilidad = las mismas relaciones sin cruces: la entidad de gran volumen arriba a la izquierda y las patas de gallo apuntando hacia arriba o hacia la izquierda."}$j$),
  (3, 'texto', $j${"title":"Las convenciones del oficio","body":"Tres convenciones ordenan cualquier ERD grande. UNO: las PATAS DE GALLO (el símbolo de 'muchos' que conociste en el módulo 1) apuntan hacia ARRIBA o hacia la IZQUIERDA — es una convención, no una ley física, pero seguirla hace que todos los diagramas del equipo se lean igual. DOS: como consecuencia, las entidades de GRAN VOLUMEN — las que acumulan filas sin descanso y se llevan las patas de gallo: CITA, MOVIMIENTO, DETALLE_PEDIDO — quedan arriba a la izquierda, donde el ojo empieza a leer. TRES: cuando el modelo supera lo que cabe en una vista, se parte en SUBDIAGRAMAS por área funcional — uno para citas, uno para farmacia, uno para personal — y una misma entidad PUEDE repetirse en varios subdiagramas: PACIENTE aparece donde haga falta, porque los subdiagramas son vistas del mismo modelo, no modelos distintos."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"En las convenciones de legibilidad de un ERD, ¿dónde se colocan las entidades de GRAN VOLUMEN (las que acumulan filas sin parar, como una CITA o un MOVIMIENTO)?","options":["Al centro exacto","Arriba a la IZQUIERDA, con las patas de gallo de sus relaciones apuntando hacia arriba o hacia la izquierda","Fuera del diagrama","Abajo a la derecha, siempre"],"correctIndex":1,"feedback":{"correct":"Correcto. La convención: gran volumen arriba-izquierda, patas de gallo hacia arriba/izquierda — y todos los diagramas del equipo se leen igual.","incorrect":"La convención del oficio coloca el gran volumen arriba a la izquierda: las patas de gallo apuntan hacia arriba o hacia la izquierda."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Dos ERD contienen exactamente las mismas entidades y relaciones, pero en uno las líneas se cruzan por todo el lienzo. ¿Cuál es la consecuencia real del 'espagueti'?","options":["Ninguna: si el contenido es correcto, da igual","El negocio no puede VALIDAR el modelo: un diagrama ilegible no se puede revisar ni aprobar, aunque sea correcto","El SQL generado sale más lento","Oracle rechaza los modelos con cruces"],"correctIndex":1,"feedback":{"correct":"Correcto. El ERD se presenta y se valida con gente: la legibilidad es requisito del proceso, no cosmética.","incorrect":"El costo es humano: un modelo que no se deja leer no se puede validar con el negocio — y un modelo sin validar es un riesgo."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Un modelo de 60 entidades no cabe legible en una sola vista. La técnica correcta es…","options":["Reducir la letra hasta que quepa","Partirlo en SUBDIAGRAMAS por área funcional — y una misma entidad puede repetirse en varios, porque son vistas del mismo modelo","Eliminar entidades hasta que quepa","Prohibir modelos de más de 20 entidades"],"correctIndex":1,"feedback":{"correct":"Correcto. Subdiagramas por dominio (citas, farmacia, personal…), con las entidades compartidas repetidas donde hagan falta.","incorrect":"Los subdiagramas por área funcional son la técnica: vistas parciales del mismo modelo, con entidades repetidas si conectan dominios."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Legibilidad","points":["El ERD se PRESENTA y se valida: la legibilidad es requisito, no adorno.","Reglas: minimizar cruces, no atravesar entidades, aire entre cajas, juntar lo muy relacionado.","Convención: patas de gallo hacia arriba o hacia la izquierda.","Entidades de GRAN VOLUMEN (CITA, MOVIMIENTO) arriba a la izquierda.","Modelos grandes → SUBDIAGRAMAS por área funcional; una entidad puede repetirse en varios."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3b-l01-legibilidad';

-- ═════════════════════════════════════════════════════════════════════
-- L02 · El mapeo: de entidades a tablas
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El puente entre dos mundos","body":"Todo lo que modelaste — entidades, atributos, UIDs, relaciones — vive en papel. El MAPEO es el puente que lo convierte en un esquema Oracle real, y sus reglas base son cuatro traducciones directas: la ENTIDAD se vuelve TABLA (convención del curso: nombre en plural — la entidad PACIENTE se vuelve la tabla pacientes); cada ATRIBUTO se vuelve COLUMNA; el UID PRIMARIO se vuelve PRIMARY KEY; y cada RELACIÓN se vuelve FOREIGN KEY. La opcionalidad que marcaste con tanto cuidado también viaja: el atributo obligatorio (*) se vuelve columna NOT NULL, y el opcional (o) se vuelve columna que admite nulos. Nada se decide dos veces: el ERD ya tomó las decisiones; el mapeo solo las ejecuta."}$j$),
  (2, 'ejemplo_sql', $j${"title":"El mapeo en acción: PACIENTE aterriza","code":"-- ERD: PACIENTE (# paciente_id, * nombre, o correo)\n--      cada paciente TIENE un médico de cabecera (obligatorio)\nCREATE TABLE pacientes (\n  paciente_id  NUMBER        CONSTRAINT pac_pk PRIMARY KEY,\n  nombre       VARCHAR2(80)  NOT NULL,       -- * obligatorio\n  correo       VARCHAR2(120),                -- o opcional\n  medico_id    NUMBER        NOT NULL\n               CONSTRAINT pac_med_fk\n               REFERENCES medicos (medico_id)\n);","result":{"columns":["RESULTADO"],"rows":[["Table PACIENTES created."]],"note":"Cada símbolo del ERD encontró su traducción: # → PRIMARY KEY, * → NOT NULL, o → columna sin NOT NULL, y la relación obligatoria con MÉDICO → la FK medico_id NOT NULL. El DDL a fondo llega en el próximo módulo; aquí importa el mapeo."}}$j$),
  (3, 'texto', $j${"title":"La FK: dónde vive y a qué apunta","body":"En una relación 1:M, la FOREIGN KEY vive SIEMPRE en el lado MUCHOS: citas lleva paciente_id — jamás al revés, porque una columna no puede guardar 'muchos pacientes'. La obligatoriedad de la relación del lado muchos decide el NOT NULL: toda cita tiene paciente → paciente_id NOT NULL; el empleado puede no tener jefe → jefe_id admite nulos. Y hablando del jefe: la relación RECURSIVA del módulo pasado se mapea como una FK que apunta a SU PROPIA tabla — jefe_id en empleados referencia empleados(empleado_id), opcional por la punta de la pirámide. Precisión que vale puntos en un examen de certificación: una FK referencia la PRIMARY KEY de la tabla destino… O una columna con restricción UNIQUE de tipo compatible. PK o UNIQUE — cualquier otra columna, jamás."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Una relación 1:M entre dos tablas ('un paciente tiene muchas citas'). ¿Dónde vive la FOREIGN KEY?","options":["En la tabla del lado UNO (pacientes)","En la tabla del lado MUCHOS (citas lleva paciente_id): una columna no puede guardar 'muchos' valores","En una tercera tabla, siempre","En ambas tablas"],"correctIndex":1,"feedback":{"correct":"Correcto. La FK siempre del lado muchos: cada cita apunta a SU paciente.","incorrect":"El lado muchos carga la FK: citas.paciente_id. Del lado uno no cabría — una columna no guarda listas."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"En el mapeo del ERD al esquema, un atributo marcado como obligatorio (*) y uno marcado como opcional (o) se convierten en…","options":["Ambos en columnas NOT NULL","El * en columna NOT NULL; el o en columna que admite nulos","El * en PRIMARY KEY; el o en FOREIGN KEY","Ambos en columnas opcionales"],"correctIndex":1,"feedback":{"correct":"Correcto. La opcionalidad decidida en el modelo viaja intacta al esquema: * → NOT NULL, o → admite nulos.","incorrect":"La traducción directa: obligatorio (*) → NOT NULL; opcional (o) → columna sin NOT NULL."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de certificación: ¿a qué puede referenciar una FOREIGN KEY en Oracle?","options":["Solo a la PRIMARY KEY de la otra tabla","A la PRIMARY KEY… o a una columna con restricción UNIQUE de tipo compatible: PK o UNIQUE, nada más","A cualquier columna de cualquier tabla","Solo a columnas NUMBER"],"correctIndex":1,"feedback":{"correct":"Correcto. PK o UNIQUE compatible: el destino debe garantizar unicidad, y esas dos restricciones son las que la garantizan.","incorrect":"El destino de una FK debe ser único: PRIMARY KEY o columna UNIQUE compatible. Una columna común no puede recibir FKs."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — El mapeo básico","points":["ENTIDAD → TABLA (plural) · ATRIBUTO → COLUMNA · UID → PRIMARY KEY · RELACIÓN → FOREIGN KEY.","La opcionalidad viaja: * → NOT NULL; o → columna que admite nulos.","En 1:M la FK vive SIEMPRE en el lado muchos (citas.paciente_id).","La recursiva se mapea como FK a su propia tabla (jefe_id → empleados), opcional en la punta.","Precisión: una FK referencia PK o columna UNIQUE compatible — nada más."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3b-l02-mapeo-basico';

-- ═════════════════════════════════════════════════════════════════════
-- L03 · Intersecciones, 1:1 y la FK en la PK
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La M:M se cobra su tabla","body":"Una relación M:M no se puede implantar directo — ninguno de los dos lados puede cargar la FK, porque ambos son 'muchos'. La solución física es la TABLA DE INTERSECCIÓN: una tabla nueva con una FK hacia cada lado, donde cada fila es UNA conexión concreta (esta receta incluye este medicamento). La PK clásica de la intersección: las dos FKs JUNTAS, como PK compuesta. Pero aquí va una precisión que separa al que diseña del que recita: 'las dos FKs como PK' NO es una ley. Si la misma pareja puede repetirse en el tiempo — la intersección HISTÓRICA del módulo pasado — la fecha ENTRA a la PK, porque las dos FKs solas prohibirían el segundo encuentro. Y si la tabla de intersección gana vida propia (atributos, hijos que la referencian), un id artificial con UNIQUE sobre la combinación puede ser el mejor diseño. La PK de la intersección se DISEÑA caso por caso; no se recita de memoria."}$j$),
  (2, 'ejemplo_sql', $j${"title":"La intersección histórica del m3a, ya en Oracle","code":"-- MÉDICO ↔ CONSULTORIO a lo largo del tiempo:\n-- las dos FKs + la fecha en la PK (la pareja puede repetirse)\nCREATE TABLE historial_asignaciones (\n  medico_id       NUMBER NOT NULL\n                  CONSTRAINT hia_med_fk REFERENCES medicos (medico_id),\n  consultorio_id  NUMBER NOT NULL\n                  CONSTRAINT hia_con_fk REFERENCES consultorios (consultorio_id),\n  fecha_inicio    DATE   NOT NULL,\n  fecha_fin       DATE,\n  CONSTRAINT hia_pk PRIMARY KEY (medico_id, consultorio_id, fecha_inicio)\n);","result":{"columns":["RESULTADO"],"rows":[["Table HISTORIAL_ASIGNACIONES created."]],"note":"El UID compuesto que diseñaste en el módulo pasado (| medico · | consultorio · # fecha_inicio) aterriza como PK de tres columnas: el mismo médico puede volver al mismo consultorio en otro período, y fecha_fin queda opcional — el período vigente aún no termina."}}$j$),
  (3, 'texto', $j${"title":"1:1 y la relación identificadora en físico","body":"Dos mapeos finos cierran la lección. El 1:1 NO genera tabla nueva: se implanta como una FK con restricción UNIQUE — si cada expediente clínico pertenece a exactamente un paciente, expedientes lleva paciente_id UNIQUE. ¿En cuál de los dos lados va la FK? En el lado más OPCIONAL: si hay pacientes sin expediente pero no expedientes sin paciente, la FK vive en expedientes — así nadie carga columnas eternamente nulas. Y la relación IDENTIFICADORA — la barra del módulo 2 — tiene su propio destino físico: la FK ENTRA a la PRIMARY KEY. La cuenta bancaria que no existe sin su banco se implanta con PK compuesta (banco_id, numero_cuenta): la dependencia existencial hecha estructura — sin padre, literalmente no hay PK posible. El historial que acabas de ver es el caso estrella: FK del dueño + fecha, juntas en la PK."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cómo se implanta físicamente una relación M:M entre dos tablas?","options":["Con una FK en cada una de las dos tablas","Con una TABLA DE INTERSECCIÓN nueva: una FK hacia cada lado, cada fila una conexión concreta","Con una columna de texto que lista los ids","No se puede implantar"],"correctIndex":1,"feedback":{"correct":"Correcto. Ningún lado puede cargar la FK (ambos son muchos): la intersección nace para cargarlas ella.","incorrect":"La M:M exige tabla de intersección: una tabla nueva con FK a cada lado. Ninguno de los dos 'muchos' puede guardar la FK."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de diseño: ¿la PK de una tabla de intersección son SIEMPRE sus dos FKs?","options":["Sí, es una ley del modelo relacional","NO: si la pareja puede repetirse en el tiempo, la fecha entra a la PK; y si la tabla gana vida propia, un id artificial + UNIQUE puede ser mejor — la PK se diseña, no se recita","No: la intersección nunca lleva PK","Sí, salvo en Oracle"],"correctIndex":1,"feedback":{"correct":"Correcto. El clásico (las 2 FKs) cubre el caso simple; la historia y la vida propia piden más. Diseñar > recitar.","incorrect":"'Las dos FKs como PK' es el caso clásico, no una ley: intersecciones históricas suman la fecha, y las que ganan vida propia pueden preferir id artificial + UNIQUE."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Una relación marcada como IDENTIFICADORA en el ERD (la barra: 'la cuenta no existe sin su banco'). Su mapeo físico correcto:","options":["Una FK común, fuera de la PK","La FK ENTRA a la PRIMARY KEY: PK compuesta (banco_id, numero_cuenta) — la dependencia existencial hecha estructura","Una tabla de intersección","Un CHECK"],"correctIndex":1,"feedback":{"correct":"Correcto. La barra promete 'te necesito para mi identidad' — y la PK compuesta cumple la promesa: sin padre no hay PK.","incorrect":"Relación identificadora → FK dentro de la PK. La barra del módulo 2 se implanta como PK compuesta que incluye la FK."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — Los mapeos especiales","points":["M:M → TABLA DE INTERSECCIÓN: una FK a cada lado, cada fila una conexión.","PRECISIÓN: la PK de la intersección NO siempre son las 2 FKs — histórica suma la fecha; con vida propia, id artificial + UNIQUE.","1:1 → FK con UNIQUE, sin tabla nueva, en el lado más OPCIONAL.","Relación identificadora (barra) → la FK entra a la PK: PK compuesta.","El historial: FK del dueño + fecha_inicio en la PK, fecha_fin opcional."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3b-l03-intersecciones';

-- ═════════════════════════════════════════════════════════════════════
-- L04 · Arcos y subtipos en físico (+ Diagrama 7.1)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El arco se implanta con vigilante","body":"El arco del módulo pasado — 'el estudio se procesa en el laboratorio PROPIO o en uno EXTERNO, exactamente uno' — plantea un reto físico: ninguna FK individual puede vigilar la exclusión, porque cada FK solo sabe de su propia tabla destino. La implantación estándar: una FK OPCIONAL por cada alternativa… más una restricción CHECK que exige que EXACTAMENTE UNA tenga valor. Las FKs garantizan que cada referencia apunte a algo real; la CHECK garantiza el OR exclusivo. Sin ella, un estudio podría tener dos laboratorios (violando la exclusión) o ninguno (violando la obligatoriedad del conjunto) — y el arco que dibujaste con tanto cuidado quedaría en promesa."}$j$),
  (2, 'ejemplo_sql', $j${"title":"El Diagrama 4.1, ya en Oracle","code":"-- El arco: dos FKs opcionales + la CHECK que vigila 'exactamente una'\nCREATE TABLE estudios_lab (\n  estudio_id      NUMBER CONSTRAINT est_pk PRIMARY KEY,\n  lab_propio_id   NUMBER CONSTRAINT est_lp_fk\n                  REFERENCES labs_propios (lab_id),\n  lab_externo_id  NUMBER CONSTRAINT est_le_fk\n                  REFERENCES labs_externos (lab_id),\n  CONSTRAINT est_arco_ck CHECK (\n    (lab_propio_id IS NOT NULL AND lab_externo_id IS NULL)\n    OR\n    (lab_propio_id IS NULL AND lab_externo_id IS NOT NULL)\n  )\n);","result":{"columns":["RESULTADO"],"rows":[["Table ESTUDIOS_LAB created."]],"note":"Nota que ninguna FK lleva NOT NULL — individualmente opcionales, como el arco manda — y la CHECK cubre los dos abusos posibles: ambas con valor (exclusión violada) y ambas nulas (obligatoriedad del conjunto violada)."}}$j$),
  (3, 'texto', $j${"title":"Subtipos: tres caminos al físico","body":"Los subtipos del m3a (PERSONAL → MEDICO, ENFERMERO, OTRO) admiten TRES implantaciones, y elegir es un intercambio clásico. A — UNA SOLA TABLA: todo el supertipo y todos los subtipos en una tabla, con una columna DISCRIMINADORA (tipo) que declara qué es cada fila, y las columnas propias de cada subtipo como opcionales. Simple y rápida para consultas conjuntas; su costo: columnas nulas y la coherencia (que un enfermero no traiga colegiatura) queda en manos de CHECKs. B — UNA TABLA POR SUBTIPO: medicos y enfermeros como tablas independientes, cada una repitiendo las columnas comunes; el supertipo desaparece. Ideal cuando los subtipos casi no comparten y JAMÁS se consultan juntos; su costo: 'todo el personal' exige unir tablas. C — SUPERTABLA + SUBTABLAS: personal con lo común; medicos y enfermeros con lo propio, y su PK es A LA VEZ FK hacia la supertabla — la PK COMPARTIDA. La más fiel al modelo y sin nulos… y la que más joins cobra. Guía rápida: subtipos parecidos y consultas conjuntas → A; mundos separados → B; fidelidad y pureza → C."}$j$),
  (4, 'diagrama', $j${"title":"Diagrama 7.1 · Tres implantaciones para los mismos subtipos","component":"NetworkDiagram","props":{"label":"PERSONAL → MEDICO / ENFERMERO: las tres estrategias","ancho":520,"alto":460,"grupos":[{"id":"est_a","x":14,"y":30,"w":492,"h":110,"titulo":"A · Una sola tabla (con discriminadora)","descripcion":"Todo en una tabla: las columnas comunes, las propias de cada subtipo (opcionales) y la columna DISCRIMINADORA que dice qué es cada fila. Rápida para consultar todo el personal junto; sus nulos son el precio."},{"id":"est_b","x":14,"y":150,"w":492,"h":110,"titulo":"B · Una tabla por subtipo","descripcion":"El supertipo desaparece: cada subtipo es una tabla completa, con lo común repetido en cada una. Perfecta si médicos y enfermeros jamás se consultan juntos; 'todo el personal' ahora exige unir tablas."},{"id":"est_c","x":14,"y":270,"w":492,"h":176,"titulo":"C · Supertabla + subtablas (PK compartida)","descripcion":"Lo común arriba, lo propio abajo, y la PK de cada subtabla es A LA VEZ FK hacia la supertabla: el mismo id identifica a la persona en ambas. La más fiel al modelo, sin columnas nulas… y la que más joins cobra."}],"nodos":[{"id":"personal_a","x":140,"y":66,"w":240,"h":56,"titulo":"personal","subtitulo":"tipo · colegiatura (o) · turno (o)","tag":"discriminadora","descripcion":"Una tabla única: la columna tipo (la discriminadora) vale 'MEDICO', 'ENFERMERO' u 'OTRO', y las columnas de subtipo son opcionales — con CHECKs si quieres vigilar la coherencia."},{"id":"medicos_b","x":60,"y":190,"w":180,"h":52,"titulo":"medicos","subtitulo":"nombre · colegiatura","descripcion":"Tabla independiente con TODO lo del médico — incluidas las columnas comunes (nombre, fecha de contratación), repetidas respecto de enfermeros."},{"id":"enfermeros_b","x":280,"y":190,"w":180,"h":52,"titulo":"enfermeros","subtitulo":"nombre · turno","descripcion":"La otra tabla independiente. Sin supertabla que las una: consultar 'todo el personal' obliga a combinar ambas."},{"id":"personal_c","x":160,"y":300,"w":200,"h":48,"titulo":"personal","subtitulo":"# personal_id · nombre","descripcion":"La supertabla: lo común de todos, una sola vez. Cada persona existe aquí primero."},{"id":"medicos_c","x":50,"y":382,"w":180,"h":48,"titulo":"medicos","subtitulo":"# personal_id · colegiatura","descripcion":"Solo lo propio del médico. Su PK (personal_id) es a la vez FK hacia personal: la PK COMPARTIDA."},{"id":"enfermeros_c","x":290,"y":382,"w":180,"h":48,"titulo":"enfermeros","subtitulo":"# personal_id · turno","descripcion":"El mismo patrón: PK = FK. El id 741 en personal y el 741 aquí son la MISMA persona."}],"enlaces":[{"de":"medicos_c","a":"personal_c","tipo":"flecha","etiqueta":"PK = FK","descripcion":"La PK de medicos referencia a personal: identidad compartida entre supertabla y subtabla."},{"de":"enfermeros_c","a":"personal_c","tipo":"flecha","etiqueta":"PK = FK","descripcion":"Igual para enfermeros: una persona, una fila arriba, a lo sumo una fila abajo."}],"hint":"Toca las tres estrategias y compara sus costos."},"caption":"Los mismos subtipos, tres físicos posibles: discriminadora con nulos (A), tablas separadas con repetición (B), o PK compartida con joins (C). Elegir es diseñar."}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cómo se implanta físicamente un ARCO ('exactamente una de estas relaciones')?","options":["Con una sola FK NOT NULL","Con una FK OPCIONAL por alternativa + una restricción CHECK que exige que exactamente UNA tenga valor","Con dos FKs NOT NULL","Con un trigger, obligatoriamente"],"correctIndex":1,"feedback":{"correct":"Correcto. Las FKs validan cada referencia; la CHECK vigila el OR exclusivo que ninguna FK sola puede ver.","incorrect":"El arco físico: FKs opcionales (una por rama) + CHECK de 'exactamente una no nula'. Sin la CHECK, el OR exclusivo queda en promesa."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"En la estrategia de subtipos de UNA SOLA TABLA, ¿qué es la columna DISCRIMINADORA?","options":["La PRIMARY KEY","La columna (por ejemplo, tipo) que declara a qué SUBTIPO pertenece cada fila: 'MEDICO', 'ENFERMERO', 'OTRO'","Una columna cifrada","La FK hacia la supertabla"],"correctIndex":1,"feedback":{"correct":"Correcto. Con todos los subtipos conviviendo en una tabla, la discriminadora es la que dice qué es cada fila.","incorrect":"La discriminadora etiqueta cada fila con su subtipo — imprescindible cuando todos comparten una sola tabla."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"En la estrategia SUPERTABLA + SUBTABLAS, ¿qué significa que la subtabla tenga 'PK compartida'?","options":["Que la subtabla no tiene PK","Que la PK de la subtabla es A LA VEZ una FK hacia la supertabla: el mismo id identifica a la instancia en ambas","Que dos subtablas comparten filas","Que la PK es un texto"],"correctIndex":1,"feedback":{"correct":"Correcto. PK = FK: el médico 741 y el personal 741 son la misma persona — la herencia del modelo, hecha llaves.","incorrect":"PK compartida: la subtabla usa como PRIMARY KEY el mismo id de la supertabla, que además es su FK. Una identidad, dos tablas."}}$j$),
  (8, 'resumen', $j${"title":"Resumen — Arcos y subtipos físicos","points":["Arco físico = FKs OPCIONALES (una por rama) + CHECK de 'exactamente una no nula'.","Subtipos, camino A: UNA TABLA con columna DISCRIMINADORA y columnas de subtipo opcionales.","Camino B: UNA TABLA POR SUBTIPO — sin supertabla, con lo común repetido.","Camino C: SUPERTABLA + SUBTABLAS con PK COMPARTIDA (la PK de la subtabla es también FK).","Elegir: parecidos y consultados juntos → A; mundos separados → B; fidelidad sin nulos (pagando joins) → C."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3b-l04-arcos-subtipos';

-- ═════════════════════════════════════════════════════════════════════
-- L05 · Nomenclatura Oracle
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"Las reglas de Oracle para los nombres","body":"Antes de crear la primera tabla, las reglas del juego. Un identificador Oracle (nombre de tabla, columna, constraint…) empieza con una LETRA y continúa con letras, dígitos y los símbolos _, $ y # — sin espacios. No puede ser una PALABRA RESERVADA: ORDER, SELECT o TABLE como nombre de tabla son rechazados. Oracle es INSENSIBLE a mayúsculas — pacientes, PACIENTES y Pacientes son el mismo objeto — salvo que escribas el nombre entre comillas dobles… lo cual te condena a usar comillas para siempre: evítalas. Y la precisión de versión que las certificaciones adoran: el límite clásico era 30 BYTES; desde Oracle 12.2 es de 128 bytes. BYTES, no caracteres — una ñ o una á puede ocupar más de un byte, otra razón para nombrar sin acentos ni eñes."}$j$),
  (2, 'texto', $j${"title":"Convenciones: la regla de las reglas es la consistencia","body":"Dentro de lo que Oracle permite, cada equipo fija su estilo — y la única regla universal es la CONSISTENCIA: un esquema donde conviven Pacientes, TBL_MEDICO y cita_x es ilegible aunque cada nombre sea válido. El estilo de este curso, que ya has visto en acción: TABLAS en plural (pacientes, citas), COLUMNAS en singular (nombre, fecha_inicio), identificadores con sufijo _id (paciente_id), y CONSTRAINTS con nombre propio y sufijo por tipo — pac_pk, pac_med_fk, epe_rfc_uk, est_arco_ck. Esto último no es capricho: si no nombras tus constraints, Oracle les inventa nombres como SYS_C0012847 — y cuando una violación explote en producción, el mensaje de error citará ese jeroglífico. Nombrar constraints es regalarle contexto a tu yo del futuro."}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Cuál de estos nombres de tabla RECHAZARÍA Oracle?","options":["historial_precios","ORDER — es una palabra reservada del lenguaje","pacientes2","gasto_$_mensual"],"correctIndex":1,"feedback":{"correct":"Correcto. Las palabras reservadas (ORDER, SELECT, TABLE…) no pueden nombrar objetos. Los otros tres cumplen las reglas.","incorrect":"El identificador debe empezar con letra, usar letras/dígitos/_/$/# y NO ser palabra reservada: ORDER está reservada (ORDER BY)."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de versión: ¿cuál es el límite de longitud de un identificador en Oracle?","options":["Siempre 30 caracteres, en todas las versiones","30 BYTES hasta la versión 12.1; 128 bytes DESDE la 12.2 — y son bytes, no caracteres","255 caracteres desde siempre","No hay límite"],"correctIndex":1,"feedback":{"correct":"Correcto. El clásico 30 se amplió a 128 en 12.2. Y en bytes: los acentos pueden ocupar más de uno.","incorrect":"30 bytes era el límite clásico; desde Oracle 12.2 son 128. Bytes, no caracteres — por eso se nombra sin acentos."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"¿Por qué conviene dar nombre propio a cada constraint (pac_pk, est_arco_ck) en lugar de dejar que Oracle lo genere?","options":["Porque los constraints sin nombre no funcionan","Porque Oracle inventaría nombres como SYS_C0012847 — y los errores de producción citarían ese jeroglífico en vez de decirte QUÉ regla se violó","Porque los nombres generados ocupan más espacio","Porque es obligatorio por sintaxis"],"correctIndex":1,"feedback":{"correct":"Correcto. La constraint funciona igual, pero el error 'pac_med_fk violada' se entiende; 'SYS_C0012847 violada' se investiga.","incorrect":"La razón es la depuración: un nombre propio convierte el error críptico en un mensaje que se entiende de inmediato."}}$j$),
  (6, 'resumen', $j${"title":"Resumen — Nomenclatura","points":["Identificador: empieza con letra; letras, dígitos, _, $, # — sin espacios ni palabras reservadas.","Insensible a mayúsculas… salvo comillas dobles: evítalas siempre.","Límite: 30 BYTES hasta 12.1 · 128 bytes desde Oracle 12.2 (bytes ≠ caracteres: sin acentos).","Estilo del curso: tablas en plural, columnas en singular, sufijo _id, constraints nombradas (pac_pk, est_arco_ck).","Constraint sin nombre = SYS_C… en el error de producción. La consistencia es la regla de las reglas."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3b-l05-nomenclatura';

-- ═════════════════════════════════════════════════════════════════════
-- L06 · El ciclo de vida y la matriz CRUD (+ Diagrama 8.1)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"El diseño vive dentro de un ciclo","body":"Todo lo que llevas del curso ocupa un lugar preciso dentro del CICLO DE VIDA del desarrollo de una base de datos (el SDLC). Etapa 1 — ESTRATEGIA Y ANÁLISIS: entrevistas con el negocio, reglas, el modelo conceptual (tus módulos 1 a 3a). Etapa 2 — DISEÑO: el ERD pulido y su mapeo a tablas (exactamente donde estás parada ahora). Etapa 3 — CONSTRUCCIÓN Y DOCUMENTACIÓN: el DDL que crea el esquema real (tu próximo módulo). Etapa 4 — TRANSICIÓN: pruebas de aceptación con usuarios, migración de datos, capacitación. Etapa 5 — PRODUCCIÓN: el sistema operando, con soporte y ajustes. La ley que gobierna el ciclo: el COSTO DE CORREGIR UN ERROR CRECE CON CADA ETAPA. La entidad olvidada cuesta una goma de borrar en análisis, un ALTER TABLE en construcción… y una migración con sistema detenido, datos que convertir y usuarios que reentrenar en producción. Por eso el modelado — la parte 'lenta' del proyecto — es en realidad la más barata."}$j$),
  (2, 'diagrama', $j${"title":"Diagrama 8.1 · El ciclo de vida (SDLC)","component":"NetworkDiagram","props":{"label":"Las cinco etapas — y el costo de corregir creciendo a cada paso","ancho":520,"alto":280,"nodos":[{"id":"analisis","x":24,"y":50,"w":148,"h":56,"titulo":"1 · ESTRATEGIA Y ANÁLISIS","descripcion":"Entrevistas, reglas de negocio, modelo conceptual. Corregir aquí cuesta una goma de borrar: solo se redibuja el diagrama."},{"id":"diseno","x":196,"y":50,"w":128,"h":56,"titulo":"2 · DISEÑO","tag":"estás aquí","descripcion":"El ERD final y su mapeo a tablas: las decisiones de este módulo. Corregir aquí sigue siendo barato — todavía es papel."},{"id":"construccion","x":348,"y":50,"w":148,"h":56,"titulo":"3 · CONSTRUCCIÓN","descripcion":"El DDL crea el esquema real y se documenta. Corregir ya cuesta código: ALTERs, scripts, re-pruebas."},{"id":"transicion","x":100,"y":180,"w":148,"h":56,"titulo":"4 · TRANSICIÓN","descripcion":"Pruebas de aceptación, migración de datos, capacitación. Un error detectado aquí obliga a rehacer pruebas y reconvertir datos."},{"id":"produccion","x":300,"y":180,"w":150,"h":56,"titulo":"5 · PRODUCCIÓN","descripcion":"El sistema en operación. La entidad olvidada cuesta aquí lo máximo: migración con downtime, conversión de datos reales y usuarios que reentrenar."}],"enlaces":[{"de":"analisis","a":"diseno","tipo":"flecha","descripcion":"Del modelo conceptual validado al diseño detallado."},{"de":"diseno","a":"construccion","tipo":"flecha","descripcion":"Del mapeo aprobado al DDL que lo construye."},{"de":"construccion","a":"transicion","tipo":"flecha","descripcion":"Del esquema construido a las pruebas con usuarios reales."},{"de":"transicion","a":"produccion","tipo":"flecha","descripcion":"De la aceptación a la operación — donde corregir cuesta lo máximo."}],"hint":"Recorre las cinco etapas: el costo de corregir crece en cada una."},"caption":"El SDLC: análisis → diseño → construcción → transición → producción. Cada etapa multiplica el costo de corregir lo que la anterior dejó pasar — por eso el modelado barato es la inversión más rentable del proyecto."}$j$),
  (3, 'texto', $j${"title":"La matriz CRUD: el detector de huecos","body":"Antes de construir, una validación barata y sistemática: la MATRIZ CRUD. Filas: los PROCESOS del negocio (agendar cita, surtir receta, contratar personal…). Columnas: las ENTIDADES del modelo. En cada celda, las letras de lo que el proceso hace con la entidad: C (Create, crear), R (Read, leer), U (Update, actualizar), D (Delete, borrar). Llena, la matriz delata los huecos que ninguna revisión al vuelo encuentra: una COLUMNA SIN C es una entidad que ningún proceso crea — ¿sobra la entidad o falta modelar un proceso?; una columna donde solo hay C es una entidad que se escribe y nadie lee jamás — ¿para qué existe?; una FILA VACÍA es un proceso del negocio que el modelo no soporta — el hueco más caro si llega a producción. Diez minutos de matriz ahorran meses de ALTERs: es el control de calidad final del diseño antes de escribir DDL."}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"En el ciclo de vida (SDLC) de una base de datos, ¿en qué etapa se realiza el MAPEO del ERD a tablas?","options":["Estrategia y análisis","DISEÑO: el ERD pulido se traduce a tablas, columnas, PKs y FKs — antes de escribir el DDL","Transición","Producción"],"correctIndex":1,"feedback":{"correct":"Correcto. Análisis produce el modelo; DISEÑO lo mapea; construcción escribe el DDL que lo materializa.","incorrect":"El mapeo es la segunda etapa: DISEÑO — después del análisis que modeló, antes de la construcción que escribe DDL."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"La 'ley del ciclo de vida' sobre los errores de diseño dice que…","options":["Todos los errores cuestan igual en cualquier etapa","El costo de corregir CRECE con cada etapa: goma de borrar en análisis, ALTER en construcción, migración con downtime en producción","Los errores solo importan en producción","Corregir en análisis es lo más caro"],"correctIndex":1,"feedback":{"correct":"Correcto. Por eso el modelado 'lento' es la parte más barata del proyecto: atrapa los errores donde corregirlos no cuesta casi nada.","incorrect":"El costo se multiplica etapa a etapa: lo que en papel es un borrón, en producción es downtime, conversión de datos y reentrenamiento."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"En una matriz CRUD (procesos en filas, entidades en columnas), una columna SIN ninguna C significa que…","options":["La entidad es de solo lectura y está perfecta","Ningún proceso CREA esa entidad: o la entidad sobra, o falta modelar el proceso que la da de alta — un hueco de diseño","La entidad tiene demasiados atributos","El proceso está duplicado"],"correctIndex":1,"feedback":{"correct":"Correcto. Una entidad que nadie crea nunca tendrá filas: la matriz delata el hueco antes de que cueste ALTERs.","incorrect":"Sin C, la entidad jamás recibe instancias: la matriz CRUD pregunta '¿sobra la entidad o falta el proceso?' antes de construir."}}$j$),
  (7, 'resumen', $j${"title":"Resumen — SDLC y matriz CRUD","points":["SDLC: 1 estrategia y análisis · 2 DISEÑO (el mapeo: aquí estás) · 3 construcción · 4 transición · 5 producción.","La ley del ciclo: el costo de corregir CRECE con cada etapa — modelar bien es la inversión más barata.","Matriz CRUD: procesos en filas × entidades en columnas; C/R/U/D en las celdas.","Columna sin C = entidad que nadie crea · solo C = nadie la lee · fila vacía = proceso sin soporte.","La matriz es el control de calidad final del diseño, antes de escribir DDL."]}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3b-l06-sdlc-crud';

-- ═════════════════════════════════════════════════════════════════════
-- L07 · Práctica: la hoja de mapeo (kind = practica)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'ejercicio', $j${"scenario":"El modelo del hospital está aprobado y toca convertirlo en esquema Oracle. Te pasaron la hoja de decisiones de mapeo: el caso 1 viene resuelto de ejemplo; completa los demás con la respuesta exacta que pide cada uno (en minúsculas, tal como aparece en las opciones).","instructions":["Caso 2 — RECETA M:M MEDICAMENTO, y la misma pareja puede repetirse en fechas distintas. PK de la tabla de intersección: ¿las_dos_fks o fks_y_fecha?","Caso 3 — ESTUDIO se procesa en laboratorio PROPIO o EXTERNO (arco). Además de las dos FKs opcionales, ¿qué restricción vigila el 'exactamente una'? (la palabra clave SQL)","Caso 4 — Subtipos MEDICO/ENFERMERO/OTRO: disjuntos, con pocos atributos propios y siempre consultados juntos. ¿una_tabla, tabla_por_subtipo o super_y_sub?","Caso 5 — En Oracle 11g (límite de 30 bytes), ¿es válido el identificador historial_asignaciones_de_consultorios, de 38 bytes? (si/no)"],"initialCode":"-- HOJA DE MAPEO — Hospital San Rafael\n\n-- Caso 1 (ejemplo): PACIENTE 1:M CITA, obligatoria del lado cita\n--   → la FK vive en el lado muchos y no admite nulos\ncaso1_fk=citas_not_null\n\n-- Caso 2: RECETA M:M MEDICAMENTO; la pareja se repite en el tiempo.\n--   PK de la intersección:\ncaso2_pk=?\n\n-- Caso 3: arco de ESTUDIO (lab propio o externo).\n--   Dos FKs opcionales + una restricción...\ncaso3_restriccion=?\n\n-- Caso 4: subtipos disjuntos, pocos atributos propios,\n--   siempre consultados juntos. Estrategia:\ncaso4_estrategia=?\n\n-- Caso 5: identificador de 38 bytes en Oracle 11g. ¿Válido?\ncaso5_valido=?","validators":["caso2_pk\\s*=\\s*fks_y_fecha\\b","caso3_restriccion\\s*=\\s*check\\b","caso4_estrategia\\s*=\\s*una_tabla\\b","caso5_valido\\s*=\\s*no\\b"],"mockOutput":{"columns":["CASO","DECISIÓN","POR QUÉ"],"rows":[["1 · PACIENTE–CITA","citas_not_null","la FK vive en el lado muchos; relación obligatoria → NOT NULL"],["2 · RECETA–MEDICAMENTO","fks_y_fecha","la pareja se repite en el tiempo: la fecha entra a la PK — las 2 FKs solas prohibirían el segundo encuentro"],["3 · arco de ESTUDIO","check","las FKs no ven a la otra: solo una CHECK vigila 'exactamente una no nula'"],["4 · subtipos de PERSONAL","una_tabla","parecidos y consultados juntos: una tabla con discriminadora gana; los nulos son el precio"],["5 · identificador de 38 bytes","no","en 11g el límite es 30 BYTES; 128 recién desde la 12.2"]],"note":"La hoja completa: cada estructura del modelo con su implantación física correcta."},"hints":["Caso 2: si la PK fuera solo las dos FKs, ¿qué pasaría cuando la misma receta repita el mismo medicamento en otra fecha? Caso 3: es la misma restricción que valida rangos y condiciones fila por fila.","Caso 4: subtipos parecidos + consultas conjuntas → la estrategia simple con columna discriminadora (una_tabla).","Caso 5: 128 bytes es cosa de Oracle 12.2 en adelante; en 11g el techo seguía en 30."],"successMessage":"Hoja de mapeo entregada: intersección histórica, arco con CHECK, subtipos con discriminadora y el límite de 30 bytes — el modelo completo ya sabe cómo aterrizar en Oracle. El próximo módulo escribe ese DDL de verdad.","failMessage":"Revisa: caso2=fks_y_fecha (la pareja se repite: la fecha entra a la PK) · caso3=check (ninguna FK ve a la otra) · caso4=una_tabla (parecidos + juntos → discriminadora) · caso5=no (en 11g el límite era 30 bytes)."}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3b-l07-practica-mapeo';

-- ═════════════════════════════════════════════════════════════════════
-- X01 · Examen de región (jefe del módulo)
-- ═════════════════════════════════════════════════════════════════════
insert into public.content_blocks (lesson_id, sort_order, kind, payload)
select l.id, v.ord, v.kind, v.payload::jsonb
from public.lessons l
join public.modules m on m.id = l.module_id
join public.courses c on c.id = m.course_id,
(values
  (1, 'texto', $j${"title":"La quinta región","body":"Byte llegó a la frontera entre dos mundos: detrás queda el papel del modelo; delante, el esquema Oracle de verdad. Once preguntas custodian el puente — legibilidad, mapeo, intersecciones, arcos, subtipos, nombres y el ciclo de vida completo. Las que falles volverán al final hasta que las domines. Adelante."}$j$),
  (2, 'quiz', $j${"variant":"multiple_choice","prompt":"Convención de legibilidad de un ERD: las entidades de GRAN VOLUMEN se colocan…","options":["Al centro del diagrama","Arriba a la IZQUIERDA, con las patas de gallo apuntando hacia arriba o hacia la izquierda","Abajo a la derecha","Fuera del diagrama principal"],"correctIndex":1,"feedback":{"correct":"Correcto. Gran volumen arriba-izquierda, patas de gallo arriba/izquierda: el estándar que unifica los diagramas del equipo.","incorrect":"La convención: entidades de gran volumen arriba a la izquierda; las patas de gallo apuntan hacia arriba o hacia la izquierda."}}$j$),
  (3, 'quiz', $j${"variant":"multiple_choice","prompt":"Las cuatro traducciones base del mapeo modelo → esquema:","options":["Entidad→columna · atributo→tabla · UID→FK · relación→PK","ENTIDAD→TABLA · ATRIBUTO→COLUMNA · UID→PRIMARY KEY · RELACIÓN→FOREIGN KEY","Entidad→vista · atributo→índice · UID→secuencia · relación→trigger","Todo se traduce a tablas"],"correctIndex":1,"feedback":{"correct":"Correcto. Las cuatro traducciones directas: el ERD decide, el mapeo ejecuta.","incorrect":"Entidad→tabla, atributo→columna, UID→PK, relación→FK: el alfabeto del mapeo."}}$j$),
  (4, 'quiz', $j${"variant":"multiple_choice","prompt":"Precisión de certificación: el destino de una FOREIGN KEY puede ser…","options":["Cualquier columna indexada","Una PRIMARY KEY o una columna UNIQUE de tipo compatible — solo esas dos, porque el destino debe garantizar unicidad","Solo una PRIMARY KEY, sin excepciones","Cualquier columna NOT NULL"],"correctIndex":1,"feedback":{"correct":"Correcto. PK o UNIQUE compatible: las dos restricciones que garantizan que la referencia apunte a UNA fila.","incorrect":"PK o UNIQUE compatible. 'Solo PK' es el error clásico de examen: una UNIQUE también puede recibir FKs."}}$j$),
  (5, 'quiz', $j${"variant":"multiple_choice","prompt":"'Toda cita pertenece a un paciente; un paciente acumula muchas citas.' El mapeo correcto de esa relación:","options":["pacientes lleva cita_id NOT NULL","citas lleva paciente_id NOT NULL: la FK vive en el lado MUCHOS, y la obligatoriedad la vuelve NOT NULL","Una tabla de intersección","citas lleva paciente_id opcional"],"correctIndex":1,"feedback":{"correct":"Correcto. FK en el lado muchos + relación obligatoria = NOT NULL. El 1:M de manual.","incorrect":"El lado muchos (citas) carga la FK, y 'toda cita tiene paciente' la hace NOT NULL."}}$j$),
  (6, 'quiz', $j${"variant":"multiple_choice","prompt":"Una tabla de intersección registra parejas que pueden REPETIRSE en fechas distintas. Su PK correcta:","options":["Las dos FKs, siempre","Las dos FKs MÁS la fecha: sin el tiempo en la PK, el segundo encuentro de la misma pareja sería un 'duplicado' prohibido","Solo la fecha","No lleva PK"],"correctIndex":1,"feedback":{"correct":"Correcto. La precisión del módulo: 'las 2 FKs como PK' es el caso clásico, no una ley — la historia mete la fecha a la PK.","incorrect":"Con las 2 FKs solas, la misma pareja no podría repetirse jamás: la fecha entra a la PK para habilitar la historia."}}$j$),
  (7, 'quiz', $j${"variant":"multiple_choice","prompt":"Mapeo de una relación 1:1 ('cada expediente pertenece a exactamente un paciente'):","options":["Una tabla de intersección","Una FK con restricción UNIQUE — colocada en el lado más OPCIONAL de la relación, para no sembrar nulos","Dos FKs NOT NULL cruzadas","Fusionar siempre las dos tablas"],"correctIndex":1,"feedback":{"correct":"Correcto. FK + UNIQUE implanta el 1:1 sin tabla nueva; el lado más opcional la carga.","incorrect":"El 1:1 físico: FK con UNIQUE (una fila destino, a lo sumo una fila origen), en el lado más opcional."}}$j$),
  (8, 'quiz', $j${"variant":"multiple_choice","prompt":"Un ARCO ('el estudio va al laboratorio propio O al externo, exactamente uno') se implanta con…","options":["Una FK NOT NULL hacia cada laboratorio","FKs OPCIONALES (una por alternativa) + una CHECK que exige exactamente UNA no nula","Una tabla de intersección","Un índice único"],"correctIndex":1,"feedback":{"correct":"Correcto. Cada FK valida su referencia; la CHECK vigila el OR exclusivo que ninguna FK puede ver sola.","incorrect":"Arco físico = FKs opcionales + CHECK de 'exactamente una no nula': sin la CHECK, la exclusividad queda sin vigilante."}}$j$),
  (9, 'quiz', $j${"variant":"multiple_choice","prompt":"En la implantación de subtipos con SUPERTABLA + SUBTABLAS, la PK de cada subtabla…","options":["Es una secuencia independiente","Es A LA VEZ FK hacia la supertabla (PK compartida): el mismo id identifica a la instancia en ambas tablas","No existe: las subtablas no llevan PK","Es la columna discriminadora"],"correctIndex":1,"feedback":{"correct":"Correcto. PK = FK: la herencia del modelo hecha llaves. (La discriminadora, en cambio, es de la estrategia de UNA sola tabla.)","incorrect":"La PK compartida define la estrategia C: la subtabla usa el id de la supertabla como PK y FK a la vez."}}$j$),
  (10, 'quiz', $j${"variant":"multiple_choice","prompt":"Sobre los identificadores Oracle, ¿cuál afirmación es correcta?","options":["El límite es 30 caracteres en todas las versiones","Empiezan con letra, admiten letras/dígitos/_/$/#, no pueden ser palabras reservadas — y el límite pasó de 30 BYTES a 128 desde la versión 12.2","Pueden contener espacios si son cortos","Las palabras reservadas se permiten en mayúsculas"],"correctIndex":1,"feedback":{"correct":"Correcto. Las reglas completas, incluida la precisión de versión: 30 bytes clásicos, 128 desde 12.2.","incorrect":"Letra inicial, letras/dígitos/_/$/#, sin reservadas; 30 bytes hasta 12.1 y 128 desde 12.2."}}$j$),
  (11, 'quiz', $j${"variant":"multiple_choice","prompt":"En una matriz CRUD terminada aparece un proceso del negocio cuya FILA está completamente vacía. Eso significa que…","options":["El proceso es de solo lectura","El modelo NO SOPORTA ese proceso: ninguna entidad le da servicio — el hueco más caro si llega a producción sin detectarse","El proceso debe eliminarse del negocio","La matriz está bien: las filas vacías son normales"],"correctIndex":1,"feedback":{"correct":"Correcto. Fila vacía = proceso sin soporte en el modelo: detectarlo en papel cuesta minutos; en producción, una migración.","incorrect":"Una fila vacía delata un proceso que el modelo no puede atender: el hallazgo más valioso de la matriz CRUD."}}$j$),
  (12, 'quiz', $j${"variant":"multiple_choice","prompt":"Pregunta final de entrevista: 'tu tabla de intersección lleva una PK de TRES columnas (las dos FKs y una fecha) en vez de las dos FKs de siempre. Defiéndelo.' Tu respuesta senior:","options":["Tres columnas dan más velocidad","Porque el negocio permite que la MISMA pareja se repita en fechas distintas: con solo las 2 FKs, el segundo encuentro sería un duplicado prohibido — la fecha en la PK habilita la historia sin perder unicidad. La PK de una intersección se diseña según las reglas del negocio, no se recita","Porque Oracle exige tres columnas como mínimo","Fue un error: la PK correcta siempre son las dos FKs"],"correctIndex":1,"feedback":{"correct":"Impecable. La PK sigue a la regla de negocio: pareja irrepetible → 2 FKs; pareja que vuelve en el tiempo → la fecha entra. Así se defiende un diseño.","incorrect":"La respuesta senior conecta PK con regla de negocio: si la pareja puede repetirse en el tiempo, la fecha DEBE entrar a la PK — el clásico de las 2 FKs solo cubre parejas irrepetibles."}}$j$)
) as v(ord, kind, payload)
where c.slug = 'sql-oracle' and l.slug = 'm3b-x01-examen';
